import React, { useState } from "react";

function FFT() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule2 = async () => {
    setLoading(true);

    try {
      const res = await fetch("http://localhost:5000/module2");
      const data = await res.json();
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Backend error");
    }

    setLoading(false);
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h2>Module 2: FFT Signature Extraction</h2>

      <button onClick={runModule2}>Run Module 2</button>

      {loading && <p>Processing...</p>}

      {result && result.status === "success" && (
        <div>
          <h3>Output</h3>
          <p>Shape: {result.shape.join(", ")}</p>

          <h3>Full FFT Table</h3>

          {/* 🔥 SCROLLABLE TABLE */}
          <div style={{
            height: "400px",
            overflow: "auto",
            border: "1px solid black"
          }}>
            <table border="1" style={{ borderCollapse: "collapse" }}>
              <thead>
                <tr>
                  <th>Row</th>
                  {result.data[0].map((_, colIndex) => (
                    <th key={colIndex}>F{colIndex}</th>
                  ))}
                </tr>
              </thead>

              <tbody>
                {result.data.map((row, rowIndex) => (
                  <tr key={rowIndex}>
                    <td>{rowIndex}</td>
                    {row.map((value, colIndex) => (
                      <td key={colIndex}>
                        {value.toFixed(3)}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>

            </table>
          </div>
        </div>
      )}
    </div>
  );
}

export default FFT;
